
const ALL_FONTS=["'Cinzel',serif","'Bebas Neue',sans-serif","'Cormorant Garamond',serif","'Playfair Display',serif","'Montserrat',sans-serif","'Dancing Script',cursive","'Orbitron',sans-serif","'Abril Fatface',serif","'Righteous',sans-serif","'Pacifico',cursive","'Oswald',sans-serif","'Permanent Marker',cursive","'Russo One',sans-serif","'Staatliches',sans-serif","'Lobster',cursive","'Bangers',cursive"];
