const GLOW_INT={off:0,low:0,med:0,high:0,ultra:0};
const SHADOW_INT={none:0,light:2,med:4,heavy:7,ultra:12};
const AR={'916':[360,640],'11':[480,480],'169':[640,360]};
const ANIM_ALL=['slam','pop','typewriter','slide_up','slide_down','slide_left','slide_right','spin','flip_x','glitch','fade_in','zoom_blur','shake','wave','stretch_h','drop_in','rise'];
const EXIT_ALL=['fade_out','slide_out_up','slide_out_down','zoom_out','scatter','shatter'];
const S={seed:0,pal:'retro_warm',fontLock:'random',glowInt:'off',strokeMode:'none',pos:'center',bgMode:'transparent',szMin:42,szMax:74,tiltMax:6,enabledAnims:new Set(ANIM_ALL),enabledExits:new Set(EXIT_ALL),wDelay:300,holdDur:1800,exitDur:500,fps:24,activeFx:new Set(['retro_grade']),fxMix:'random',perLetter:false,letterStagger:55,partCount:14,shakeX:0,shakeY:0,shadowStyle:'hard',shadowInt:'none',shadowColor:'dark',shadowX:4,shadowY:4,shadowRand:true,shadowColRand:false};
let canvas=document.getElementById('c'),ctx=canvas.getContext('2d');
let raf=null,particles=[],flashState={active:false,color:'#fff',alpha:0},globalTime=0;
let globalSeed=Math.floor(Math.random()*999999);
function mkRng(s){let x=s^0xdeadbeef;return()=>{x=Math.imul(x^x>>>16,0x45d9f3b);x=Math.imul(x^x>>>16,0x45d9f3b);x^=x>>>16;return(x>>>0)/4294967296};}

// ─── CLEAN RETRO FX — no glow, no blur, sharp shadows only ───────────────

// ─── SHARP SHADOW DRAW ────────────────────────────────────────────────────
// Shadow ox/oy/col are PRE-BAKED into each word at buildLineData.
// drawSharpShadow reads frozen values — zero RNG calls during render.
function drawSharpShadow(x, y, w, text, sz, color, wordObj){
  const base = SHADOW_INT[S.shadowInt]||0;
  if(base===0) return;
  const ox   = wordObj ? wordObj._shadowOx : S.shadowX;
  const oy   = wordObj ? wordObj._shadowOy : S.shadowY;
  const scol = wordObj ? wordObj._shadowCol : '#1a1008';
  ctx.fillStyle = scol;
  ctx.shadowBlur = 0;
  switch(S.shadowStyle){
    case 'hard':
    case 'diagonal':
      ctx.fillText(text, x+ox, y+oy);
      break;
    case 'long':
      for(let i=base*2; i>0; i--){
        ctx.globalAlpha *= .85;
        ctx.fillText(text, x + i*ox/base, y + i*oy/base);
        ctx.globalAlpha /= .85;
      }
      break;
    case 'double':
      ctx.fillText(text, x+ox*1.8, y+oy*1.8);
      ctx.globalAlpha *= .5;
      ctx.fillText(text, x+ox*.8, y+oy*.8);
      ctx.globalAlpha /= .5;
      break;
    case 'inset':
      ctx.fillStyle = lighten(color, .4);
      ctx.fillText(text, x-1, y-1);
      ctx.fillStyle = scol;
      ctx.fillText(text, x+ox, y+oy);
      break;
    case 'stacked':
      for(let i=base; i>0; i--){
        ctx.fillText(text, x + (ox/base)*i, y + (oy/base)*i);
      }
      break;
  }
}

// Flat solid fill — crisp and clean
function fxFlat(x,y,text,color,wordObj){
  ctx.shadowBlur=0;
  drawSharpShadow(x,y,0,text,0,color,wordObj);
  ctx.fillStyle=color;
  ctx.fillText(text,x,y);
}

// Retro color grade — darker base + lighter highlight on top portion
function fxRetroGrade(x,y,w,text,sz,color,color2,wordObj){
  ctx.shadowBlur=0;
  drawSharpShadow(x,y,w,text,sz,color,wordObj);
  // Snapshot font — ctx.restore() will wipe it
  const _f=ctx.font,_a=ctx.textAlign,_b=ctx.textBaseline;
  // Base: full word, slightly darker
  ctx.fillStyle=darken(color,.14);
  ctx.fillText(text,x,y);
  // Highlight: clip to top ~40% of glyph height
  ctx.save();
  ctx.beginPath();
  ctx.rect(x - w*0.55, y - sz*0.88, w*1.1, sz*0.42);
  ctx.clip();
  ctx.font=_f; ctx.textAlign=_a; ctx.textBaseline=_b;
  ctx.fillStyle=lighten(color,.26);
  ctx.fillText(text,x,y);
  ctx.restore();
  ctx.font=_f; ctx.textAlign=_a; ctx.textBaseline=_b;
}

// Duotone — left/right colour split
function fxDuotone(x,y,w,text,sz,color,color2,wordObj){
  ctx.shadowBlur=0;
  drawSharpShadow(x,y,w,text,sz,color,wordObj);
  const _f=ctx.font,_a=ctx.textAlign,_b=ctx.textBaseline;
  const hw=w*0.52+2;
  // Left half
  ctx.save();
  ctx.beginPath();
  ctx.rect(x - hw, y - sz*1.05, hw, sz*1.35);
  ctx.clip();
  ctx.font=_f; ctx.textAlign=_a; ctx.textBaseline=_b;
  ctx.fillStyle=color;
  ctx.fillText(text,x,y);
  ctx.restore();
  ctx.font=_f; ctx.textAlign=_a; ctx.textBaseline=_b;
  // Right half
  ctx.save();
  ctx.beginPath();
  ctx.rect(x, y - sz*1.05, hw, sz*1.35);
  ctx.clip();
  ctx.font=_f; ctx.textAlign=_a; ctx.textBaseline=_b;
  ctx.fillStyle=color2||shift(color,30);
  ctx.fillText(text,x,y);
  ctx.restore();
  ctx.font=_f; ctx.textAlign=_a; ctx.textBaseline=_b;
}

// Stamp — solid color with clean dark outline, like letterpress
function fxStamp(x,y,text,sz,color,wordObj){
  ctx.shadowBlur=0;
  drawSharpShadow(x,y,0,text,sz,color,wordObj);
  ctx.strokeStyle=darken(color,.45);
  ctx.lineWidth=sz*.06;
  ctx.lineJoin='round';
  ctx.strokeText(text,x,y);
  ctx.fillStyle=color;
  ctx.fillText(text,x,y);
}

// Outline — hollow text with retro stroke
function fxOutline(x,y,text,sz,color,wordObj){
  ctx.shadowBlur=0;
  drawSharpShadow(x,y,0,text,sz,color,wordObj);
  ctx.strokeStyle=color;
  ctx.lineWidth=sz*.07;
  ctx.lineJoin='round';
  ctx.strokeText(text,x,y);
}

// Offset / double print — risograph feel
function fxOffset(x,y,text,sz,color,color2,wordObj){
  ctx.shadowBlur=0;
  drawSharpShadow(x,y,0,text,sz,color,wordObj);
  const off=Math.round(sz*.05);
  ctx.globalAlpha*=.55;
  ctx.fillStyle=color2||shift(color,40);
  ctx.fillText(text,x+off,y+off);
  ctx.globalAlpha/=.55;
  ctx.fillStyle=color;
  ctx.fillText(text,x,y);
}

// ─── COLOR HELPERS ────────────────────────────────────────────────────────
function hexToRgb(hex){
  const r=parseInt(hex.slice(1,3),16),g=parseInt(hex.slice(3,5),16),b=parseInt(hex.slice(5,7),16);
  return[r,g,b];
}
function rgbToHex(r,g,b){
  return'#'+[r,g,b].map(v=>Math.max(0,Math.min(255,Math.round(v))).toString(16).padStart(2,'0')).join('');
}
function lighten(hex,amt){
  try{const[r,g,b]=hexToRgb(hex);return rgbToHex(r+(255-r)*amt,g+(255-g)*amt,b+(255-b)*amt);}catch{return hex;}
}
function darken(hex,amt){
  try{const[r,g,b]=hexToRgb(hex);return rgbToHex(r*(1-amt),g*(1-amt),b*(1-amt));}catch{return hex;}
}
function shift(hex,deg){
  try{
    const[r,g,b]=hexToRgb(hex);
    const max=Math.max(r,g,b)/255,min=Math.min(r,g,b)/255;
    let h=0,s=0,l=(max+min)/2;
    const d=max-min;
    if(d>0){s=d/(1-Math.abs(2*l-1));const rm=r/255,gm=g/255,bm=b/255;const mx=Math.max(rm,gm,bm);
      if(mx===rm)h=((gm-bm)/d)%6;else if(mx===gm)h=(bm-rm)/d+2;else h=(rm-gm)/d+4;h*=60;}
    h=(h+deg+360)%360;
    const c=(1-Math.abs(2*l-1))*s,x=c*(1-Math.abs((h/60)%2-1)),m=l-c/2;
    let ro=0,go=0,bo=0;
    if(h<60){ro=c;go=x;}else if(h<120){ro=x;go=c;}else if(h<180){go=c;bo=x;}
    else if(h<240){go=x;bo=c;}else if(h<300){ro=x;bo=c;}else{ro=c;bo=x;}
    return rgbToHex((ro+m)*255,(go+m)*255,(bo+m)*255);
  }catch{return hex;}
}

function renderFx(fx,x,y,w,text,font,sz,color,glowColor,time,wordObj){
  ctx.shadowBlur=0;
  ctx.font=`900 ${sz}px ${font}`;ctx.textAlign='center';ctx.textBaseline='alphabetic';
  const c2=glowColor||shift(color,25);
  switch(fx){
    case 'flat':        fxFlat(x,y,text,color,wordObj);break;
    case 'retro_grade': fxRetroGrade(x,y,w,text,sz,color,c2,wordObj);break;
    case 'duotone':     fxDuotone(x,y,w,text,sz,color,c2,wordObj);break;
    case 'stamp':       fxStamp(x,y,text,sz,color,wordObj);break;
    case 'outline':     fxOutline(x,y,text,sz,color,wordObj);break;
    case 'offset':      fxOffset(x,y,text,sz,color,c2,wordObj);break;
    // legacy aliases
    case 'gold':        fxRetroGrade(x,y,w,text,sz,'#c8a028','#e8d090',wordObj);break;
    case 'chrome':      fxRetroGrade(x,y,w,text,sz,'#909090','#e0e0e0',wordObj);break;
    case 'neon':        fxFlat(x,y,text,color,wordObj);break;
    case 'holo':        fxDuotone(x,y,w,text,sz,color,c2,wordObj);break;
    case 'fire':        fxRetroGrade(x,y,w,text,sz,'#c04838','#e8a828',wordObj);break;
    case 'ice':         fxRetroGrade(x,y,w,text,sz,'#6898c8','#b8d8f0',wordObj);break;
    case 'glitch_fx':   fxOffset(x,y,text,sz,color,c2,wordObj);break;
    case 'shadow':      fxStamp(x,y,text,sz,color,wordObj);break;
    case 'glass':       fxOutline(x,y,text,sz,color,wordObj);break;
    case 'retro':       fxStamp(x,y,text,sz,color,wordObj);break;
    default:
      drawSharpShadow(x,y,w,text,sz,color,wordObj);
      ctx.fillStyle=color;ctx.fillText(text,x,y);
  }
}

// ─── PARTICLES ─────────────────────────────────────────────────────────────
function spawnParticles(x,y,color,count){
  const shapes=['circle','star','diamond','spark'];
  for(let i=0;i<count;i++){
    const a=Math.random()*Math.PI*2,spd=1+Math.random()*5.5;
    particles.push({x,y,vx:Math.cos(a)*spd,vy:Math.sin(a)*spd-1.5,life:1,decay:.028+Math.random()*.04,r:1.5+Math.random()*4,color,shape:shapes[Math.floor(Math.random()*shapes.length)]});
  }
}
function updateParticles(){particles=particles.filter(p=>{p.x+=p.vx;p.y+=p.vy;p.vy+=.11;p.life-=p.decay;return p.life>0});}
function drawParticles(){
  particles.forEach(p=>{
    ctx.save();ctx.globalAlpha=p.life*.88;ctx.fillStyle=p.color;ctx.translate(p.x,p.y);
    if(p.shape==='star'){ctx.beginPath();for(let i=0;i<5;i++){ctx.lineTo(Math.cos((i*4*Math.PI/5)-Math.PI/2)*p.r,Math.sin((i*4*Math.PI/5)-Math.PI/2)*p.r);}ctx.closePath();ctx.fill();}
    else if(p.shape==='diamond'){ctx.beginPath();ctx.moveTo(0,-p.r);ctx.lineTo(p.r*.6,0);ctx.lineTo(0,p.r);ctx.lineTo(-p.r*.6,0);ctx.closePath();ctx.fill();}
    else if(p.shape==='spark'){ctx.beginPath();ctx.moveTo(-p.r*.2,-p.r*1.5);ctx.lineTo(p.r*.2,0);ctx.lineTo(-p.r*.2,p.r*1.5);ctx.closePath();ctx.fill();}
    else{ctx.beginPath();ctx.arc(0,0,p.r,0,Math.PI*2);ctx.fill();}
    ctx.restore();
  });
}

// ─── BUILD LINE ─────────────────────────────────────────────────────────────
function buildLineData(lineObj,lineSeed){
  const r=mkRng(lineSeed);
  const words=lineObj.text.split(' ').filter(w=>w);
  const pal=PALETTES[S.pal]||PALETTES.retro_warm;
  const enabledA=[...S.enabledAnims];if(!enabledA.length)enabledA.push('fade_in');
  const enabledE=[...S.enabledExits];if(!enabledE.length)enabledE.push('fade_out');
  const exitAnim=enabledE[Math.floor(r()*enabledE.length)];
  const bgFlash=r()>.6?pal[Math.floor(r()*pal.length)]:null;
  const fxList=[...S.activeFx];if(!fxList.length)fxList.push('retro_grade');
  const szRange=S.szMax-S.szMin;
  const wordData=words.map((w,i)=>{
    const wr=mkRng(lineSeed*31+i*179);
    const useFont=S.fontLock==='random'?ALL_FONTS[Math.floor(wr()*ALL_FONTS.length)]:S.fontLock;
    const color=pal[Math.floor(wr()*pal.length)];
    const glowColor=pal[Math.floor(wr()*pal.length)];
    const anim=enabledA[Math.floor(wr()*enabledA.length)];
    const sz=document.getElementById('togRandSize').checked?Math.round(S.szMin+wr()*szRange):Math.round((S.szMin+S.szMax)/2);
    const tilt=document.getElementById('togTilt').checked?(wr()-.5)*S.tiltMax*Math.PI/180:0;
    let fx;
    if(S.fxMix==='random')fx=fxList[Math.floor(wr()*fxList.length)];
    else if(S.fxMix==='single')fx=fxList[0];
    else fx=fxList[i%fxList.length];
    // Bake shadow values ONCE — never recalculated during animation
    const _sr=mkRng(lineSeed*137+i*251+9999);
    const _shadowOx=S.shadowX*(S.shadowRand?(_sr()*0.6+0.7):1);
    const _shadowOy=S.shadowY*(S.shadowRand?(_sr()*0.6+0.7):1);
    const _shadowCol=(()=>{
      if(S.shadowColRand)          return shift(color,_sr()*360|0);
      if(S.shadowColor==='match')  return darken(color,.45);
      if(S.shadowColor==='warm')   return '#6a3010';
      if(S.shadowColor==='cool')   return '#203860';
      if(S.shadowColor==='random') return shift(color,_sr()*360|0);
      return '#1a1008';
    })();
    return{text:w,font:useFont,color,glowColor,anim,size:sz,rotation:tilt,fx,delay:i*S.wDelay,particle:document.getElementById('togParticle').checked&&wr()>.3,_particled:false,entered:false,_shadowOx,_shadowOy,_shadowCol};
  });
  return{words:wordData,exitAnim,bgFlash,speaker:lineObj.speaker};
}

// ─── LAYOUT ─────────────────────────────────────────────────────────────────
function layoutWords(ld){
  const W=canvas.width,H=canvas.height;
  ld.words.forEach(w=>{ctx.font=`900 ${w.size}px ${w.font}`;w.measuredW=ctx.measureText(w.text).width;});
  const maxW=W*.88;const rows=[];let cur=[],cw=0;
  ld.words.forEach(w=>{const need=w.measuredW+(cur.length?10:0);if(cw+need>maxW&&cur.length){rows.push(cur);cur=[w];cw=w.measuredW;}else{if(cur.length)cw+=10;cur.push(w);cw+=w.measuredW;}});
  if(cur.length)rows.push(cur);
  const maxSz=Math.max(...ld.words.map(w=>w.size));
  const lineH=maxSz*1.32;const totalH=rows.length*lineH;
  let baseY=S.pos.includes('top')?H*.1+maxSz*.5:S.pos.includes('bot')?H*.9-totalH+maxSz*.5:H/2-totalH/2+maxSz*.5;
  rows.forEach((row,ri)=>{
    const rowW=row.reduce((s,w)=>s+w.measuredW,0)+(row.length-1)*10;
    let x=S.pos.includes('left')?W*.06:S.pos.includes('right')?W*.94-rowW:(W-rowW)/2;
    const y=baseY+ri*lineH;
    row.forEach(w=>{w.x=x+w.measuredW/2;w.y=y;x+=w.measuredW+10;});
  });
}

// ─── EASING ──────────────────────────────────────────────────────────────────
function eOut(t){return 1-Math.pow(1-Math.min(1,t),3)}
function eBounce(t){t=Math.min(1,t);if(t<1/2.75)return 7.5625*t*t;if(t<2/2.75){t-=1.5/2.75;return 7.5625*t*t+.75}if(t<2.5/2.75){t-=2.25/2.75;return 7.5625*t*t+.9375}t-=2.625/2.75;return 7.5625*t*t+.984375;}
function getTransform(anim,t){
  const e=eOut(t),eb=eBounce(t);
  switch(anim){
    case 'slam':return{sx:4-e*3,sy:4-e*3,ox:0,oy:0,rot:0,alpha:Math.min(1,t*3)};
    case 'pop':{const ps=t<.6?(t/.6)*1.35:(1+(1-t/.4)*.35);return{sx:ps,sy:ps,ox:0,oy:0,rot:0,alpha:Math.min(1,t*4)};}
    case 'slide_up':return{sx:1,sy:1,ox:0,oy:(1-e)*90,rot:0,alpha:e};
    case 'slide_down':return{sx:1,sy:1,ox:0,oy:-(1-e)*90,rot:0,alpha:e};
    case 'slide_left':return{sx:1,sy:1,ox:-(1-e)*130,oy:0,rot:0,alpha:e};
    case 'slide_right':return{sx:1,sy:1,ox:(1-e)*130,oy:0,rot:0,alpha:e};
    case 'spin':return{sx:1,sy:1,ox:0,oy:0,rot:(1-e)*Math.PI*2,alpha:e};
    case 'flip_x':return{sx:1,sy:1,ox:0,oy:0,skewX:(1-e)*1.3,alpha:e};
    case 'glitch':{const gs=t<.7?(Math.random()-.5)*10:0;return{sx:1,sy:1,ox:gs,oy:(Math.random()-.5)*(1-t)*5,rot:0,alpha:t<.3?t*3.3:1};}
    case 'fade_in':return{sx:1,sy:1,ox:0,oy:0,rot:0,alpha:e};
    case 'zoom_blur':return{sx:1+(1-e)*2.2,sy:1+(1-e)*2.2,ox:0,oy:0,rot:0,alpha:e};
    case 'shake':{const sh=t<.5?Math.sin(t*50)*14*(1-t*2):0;return{sx:1,sy:1,ox:sh,oy:0,rot:0,alpha:1};}
    case 'stretch_h':{const str=t<.5?(3-eOut(t)*2.5):1;return{sx:str,sy:2-str,ox:0,oy:0,rot:0,alpha:Math.min(1,t*3)};}
    case 'drop_in':return{sx:1,sy:1,ox:0,oy:-(1-eb)*220,rot:0,alpha:Math.min(1,t*4)};
    case 'rise':return{sx:1,sy:1,ox:0,oy:(1-eb)*70,rot:0,alpha:e};
    case 'wave':return{sx:1,sy:1,ox:0,oy:Math.sin(t*Math.PI*2)*12*(1-t),rot:0,alpha:e};
    case 'typewriter':return{sx:1,sy:1,ox:0,oy:0,rot:0,alpha:1,clip:t};
    default:return{sx:1,sy:1,ox:0,oy:0,rot:0,alpha:e};
  }
}

// ─── DRAW WORD ────────────────────────────────────────────────────────────────
function drawWord(w,progress,time){
  if(progress<=0)return false;
  const t=Math.min(1,progress/380);
  const tr=getTransform(w.anim,t);
  const alpha=Math.max(0,Math.min(1,tr.alpha));
  const breathe=document.getElementById('togBreathe').checked&&t>=1?1+Math.sin(time*.0025)*.012:1;
  ctx.save();ctx.globalAlpha=alpha;
  if(S.shakeX)ctx.translate(S.shakeX,S.shakeY);
  ctx.translate(w.x+(tr.ox||0),w.y+(tr.oy||0));
  if(tr.rot)ctx.rotate(tr.rot);
  if(tr.skewX)ctx.transform(1,0,tr.skewX,1,0,0);
  ctx.rotate(w.rotation||0);
  const sx=(tr.sx||1)*breathe,sy=(tr.sy||1)*breathe;
  if(sx!==1||sy!==1)ctx.scale(sx,sy);

  const useLetters=document.getElementById('togLetters').checked;
  if(useLetters){
    drawLetters(w,tr,time);
  } else {
    ctx.font=`900 ${w.size}px ${w.font}`;ctx.textAlign='center';ctx.textBaseline='alphabetic';
    if(tr.clip!==undefined){
      ctx.save();ctx.beginPath();ctx.rect(-w.measuredW/2,-(w.size+10),w.measuredW*tr.clip+2,w.size+20);ctx.clip();
      renderFx(w.fx,0,0,w.measuredW,w.text,w.font,w.size,w.color,w.glowColor,time,w);ctx.restore();
    } else {
      renderFx(w.fx,0,0,w.measuredW,w.text,w.font,w.size,w.color,w.glowColor,time,w);
    }
    if(S.strokeMode!=='none'){ctx.font=`900 ${w.size}px ${w.font}`;ctx.textAlign='center';ctx.textBaseline='alphabetic';ctx.strokeStyle=S.strokeMode==='color'?w.glowColor:'rgba(0,0,0,.75)';ctx.lineWidth=S.strokeMode==='thick'?4:1.5;ctx.lineJoin='round';ctx.strokeText(w.text,0,0);}
  }
  ctx.restore();
  if(t>.06&&t<.18&&w.particle&&!w._particled){
    w._particled=true;
    const pal=PALETTES[S.pal]||PALETTES.luxury;
    spawnParticles(w.x,w.y-w.size*.45,pal[Math.floor(Math.random()*pal.length)],S.partCount);
    if(document.getElementById('togShake').checked&&w.anim==='slam'){S.shakeX=(Math.random()-.5)*7;S.shakeY=(Math.random()-.5)*7;setTimeout(()=>{S.shakeX=0;S.shakeY=0;},80);}
  }
  return t>=1;
}

// ─── PER-LETTER ──────────────────────────────────────────────────────────────
function drawLetters(w,tr,time){
  const letters=[...w.text];
  const pal=PALETTES[S.pal]||PALETTES.luxury;
  ctx.font=`900 ${w.size}px ${w.font}`;
  const widths=letters.map(l=>ctx.measureText(l).width);
  const totalW=widths.reduce((s,v)=>s+v,0);
  let lx=-totalW/2;
  letters.forEach((letter,li)=>{
    const lw=widths[li];const lcx=lx+lw/2;lx+=lw;
    const lColor=document.getElementById('togLetterColor').checked?pal[li%pal.length]:w.color;
    const stagger=document.getElementById('togLetterStagger').checked;
    const lAlpha=stagger?Math.min(1,Math.max(0,(tr.alpha-(li*.08))*3)):tr.alpha;
    ctx.save();ctx.globalAlpha*=lAlpha;
    ctx.translate(lcx,0);
    if(document.getElementById('togBreathe').checked){ctx.translate(0,Math.sin(time*.004+li*.65)*2.8);}
    ctx.font=`900 ${w.size}px ${w.font}`;ctx.textAlign='center';ctx.textBaseline='alphabetic';
    renderFx(w.fx,0,0,lw,letter,w.font,w.size,lColor,lColor,time+li*180,w);
    ctx.restore();
  });
}

// ─── BG / FLASH ──────────────────────────────────────────────────────────────
function drawBg(){
  if(document.getElementById('togTransparent').checked)return;
  if(S.bgMode==='grad1'){const g=ctx.createLinearGradient(0,0,canvas.width,canvas.height);g.addColorStop(0,'#e8d8c0');g.addColorStop(1,'#d0b898');ctx.fillStyle=g;}
  else if(S.bgMode==='grad2'){const g=ctx.createLinearGradient(0,0,canvas.width,canvas.height);g.addColorStop(0,'#dce4d8');g.addColorStop(1,'#c8d4c0');ctx.fillStyle=g;}
  else if(S.bgMode==='transparent')return;
  else ctx.fillStyle=S.bgMode;
  ctx.fillRect(0,0,canvas.width,canvas.height);
}
function triggerFlash(c){if(!document.getElementById('togFlash').checked)return;flashState={active:true,color:c,alpha:.18};}
function drawFlash(){if(!flashState.active)return;ctx.globalAlpha=flashState.alpha;ctx.fillStyle=flashState.color;ctx.fillRect(0,0,canvas.width,canvas.height);ctx.globalAlpha=1;flashState.alpha*=.7;if(flashState.alpha<.003)flashState.active=false;}

// ─── EXIT ─────────────────────────────────────────────────────────────────────
function drawExit(ld,t){
  const e=eOut(t);
  ld.words.forEach(w=>{
    if(!w.entered)return;
    ctx.save();ctx.globalAlpha=Math.max(0,1-e*1.3);ctx.translate(w.x,w.y);
    switch(ld.exitAnim){
      case 'slide_out_up':ctx.translate(0,-e*130);break;
      case 'slide_out_down':ctx.translate(0,e*130);break;
      case 'zoom_out':ctx.scale(1+e*2.5,1+e*2.5);break;
      case 'scatter':ctx.translate((Math.random()-.5)*e*260,(Math.random()-.5)*e*260);break;
      case 'shatter':ctx.rotate((Math.random()-.5)*e*2);ctx.translate(0,e*90);break;
    }
    ctx.rotate(w.rotation||0);
    ctx.font=`900 ${w.size}px ${w.font}`;ctx.textAlign='center';ctx.textBaseline='alphabetic';
    renderFx(w.fx,0,0,w.measuredW,w.text,w.font,w.size,w.color,w.glowColor,globalTime);ctx.restore();
  });
}

// ─── PARSE ────────────────────────────────────────────────────────────────────
function parseScript(raw){return raw.split('\n').map(l=>l.trim()).filter(l=>l).map(l=>{if(l.startsWith(':'))return{speaker:null,text:l.slice(1).trim()};const i=l.indexOf(':');if(i>0)return{speaker:l.slice(0,i).trim(),text:l.slice(i+1).trim()};return{speaker:null,text:l};});}

// ─── STATS ───────────────────────────────────────────────────────────────────
function updateStats(){
  const lines=parseScript(document.getElementById('scriptInput').value);
  const words=lines.reduce((s,l)=>s+l.text.split(' ').filter(w=>w).length,0);
  let ms=0;lines.forEach(l=>{const wc=l.text.split(' ').filter(w=>w).length;ms+=wc*S.wDelay+700+S.holdDur+S.exitDur;});
  document.getElementById('statLines').textContent=lines.length;
  document.getElementById('statWords').textContent=words;
  document.getElementById('statDur').textContent=(ms/1000).toFixed(1)+'s';
  document.getElementById('statFrames').textContent=Math.round((ms/1000)*S.fps);
}

// ─── MAIN LOOP ───────────────────────────────────────────────────────────────
function startAnim(){
  if(raf)cancelAnimationFrame(raf);
  particles=[];flashState.active=false;
  const lines=parseScript(document.getElementById('scriptInput').value);
  if(!lines.length)return;
  const ldArr=lines.map((l,i)=>buildLineData(l,globalSeed*997+i*3571));
  ldArr.forEach(ld=>layoutWords(ld));
  const lq=document.getElementById('lineQueue');lq.innerHTML='';
  lines.forEach((_,i)=>{const d=document.createElement('div');d.className='lq-dot';d.id=`lqdot${i}`;lq.appendChild(d);});
  let li=0,phase='in',phaseStart=null,wordTimers=[],lastF=null;
  function startLine(idx){
    li=idx;phase='in';phaseStart=null;
    const ld=ldArr[idx];ld.words.forEach(w=>{w._particled=false;w.entered=false;});
    wordTimers=ld.words.map(()=>({started:false,startTime:null}));
    if(ld.bgFlash)triggerFlash(ld.bgFlash);
    document.getElementById('animInfo').textContent=`LINE ${idx+1} · ${ld.exitAnim.replace(/_/g,' ').toUpperCase()}`;
    document.querySelectorAll('.lq-dot').forEach((d,i)=>{d.classList.toggle('active',i===idx);d.classList.toggle('done',i<idx);});
  }
  startLine(0);
  function frame(now){
    if(!lastF)lastF=now;lastF=now;globalTime=now;
    ctx.clearRect(0,0,canvas.width,canvas.height);drawBg();drawFlash();updateParticles();drawParticles();
    const ld=ldArr[li];if(!phaseStart)phaseStart=now;const elapsed=now-phaseStart;
    if(phase==='in'){
      let allIn=true;
      ld.words.forEach((w,i)=>{
        const wt=wordTimers[i];
        if(!wt.started&&elapsed>=i*S.wDelay){wt.started=true;wt.startTime=now;}
        if(!wt.started){allIn=false;return;}
        const done=window.drawWord(w,now-wt.startTime,now);
        if(done)w.entered=true;else allIn=false;
      });
      if(allIn&&elapsed>(ld.words.length*S.wDelay)+440){phase='hold';phaseStart=now;}
    } else if(phase==='hold'){
      ld.words.forEach(w=>window.drawWord(w,9999,now));
      if(elapsed>=S.holdDur){phase='out';phaseStart=now;}
    } else if(phase==='out'){
      const t=Math.min(1,elapsed/S.exitDur);
      drawExit(ld,t);if(elapsed>=S.exitDur)startLine((li+1)%ldArr.length);
    }
    raf=requestAnimationFrame(frame);
  }
  raf=requestAnimationFrame(frame);updateStats();
}

// ─── SHARED RENDER ENGINE ────────────────────────────────────────────────────
// Renders all frames onto an offscreen canvas, calling onFrame(offCanvas, pct) each frame
async function renderAllFrames(onFrame, onDone){
  const lines=parseScript(document.getElementById('scriptInput').value);
  if(!lines.length){ alert('No script lines to export!'); return false; }

  if(raf) cancelAnimationFrame(raf);

  const FPS=S.fps;
  const frameDurMs=1000/FPS;

  const offCanvas=document.createElement('canvas');
  offCanvas.width=canvas.width; offCanvas.height=canvas.height;
  const offCtx=offCanvas.getContext('2d');

  const _realCanvas=canvas, _realCtx=ctx;
  canvas=offCanvas; ctx=offCtx;

  const ldArr=lines.map((l,i)=>buildLineData(l,globalSeed*997+i*3571));
  ldArr.forEach(ld=>layoutWords(ld));

  const totalFrameCount=ldArr.reduce((sum,ld)=>{
    return sum+Math.ceil((ld.words.length*S.wDelay+700)/frameDurMs)
              +Math.ceil(S.holdDur/frameDurMs)
              +Math.ceil(S.exitDur/frameDurMs);
  },0);

  let fakeTime=0, totalFrames=0;

  for(let idx=0;idx<ldArr.length;idx++){
    const ld=ldArr[idx];
    ld.words.forEach(w=>{w._particled=false;w.entered=false;});
    const inF=Math.ceil((ld.words.length*S.wDelay+700)/frameDurMs);
    const hF=Math.ceil(S.holdDur/frameDurMs);
    const eF=Math.ceil(S.exitDur/frameDurMs);

    for(let f=0;f<inF;f++){
      const el=(f/FPS)*1000; fakeTime+=frameDurMs;
      offCtx.clearRect(0,0,offCanvas.width,offCanvas.height); window.drawBg();
      ld.words.forEach((w,i)=>{const wS=i*S.wDelay;if(el<wS)return;const prog=(el-wS)*1.4;window.drawWord(w,prog,fakeTime);if(prog>380)w.entered=true;});
      totalFrames++;
      await onFrame(offCanvas, Math.round(totalFrames/totalFrameCount*100), totalFrames);
    }
    for(let f=0;f<hF;f++){
      fakeTime+=frameDurMs;
      offCtx.clearRect(0,0,offCanvas.width,offCanvas.height); window.drawBg();
      ld.words.forEach(w=>window.drawWord(w,9999,fakeTime));
      totalFrames++;
      await onFrame(offCanvas, Math.round(totalFrames/totalFrameCount*100), totalFrames);
    }
    for(let f=0;f<eF;f++){
      fakeTime+=frameDurMs;
      offCtx.clearRect(0,0,offCanvas.width,offCanvas.height); window.drawBg();
      drawExit(ld,f/eF);
      totalFrames++;
      await onFrame(offCanvas, Math.round(totalFrames/totalFrameCount*100), totalFrames);
    }
  }

  canvas=_realCanvas; ctx=_realCtx;
  await onDone(totalFrames);
  startAnim();
  return true;
}

function setExportProgress(pct, txt){
  const bar=document.getElementById('exportProgressBar');
  const label=document.getElementById('exportProgressTxt');
  const wrap=document.getElementById('exportProgress');
  if(wrap) wrap.style.display='block';
  if(bar) bar.style.width=pct+'%';
  if(label) label.textContent=txt;
}
function hideExportProgress(){ const w=document.getElementById('exportProgress'); if(w) w.style.display='none'; }
function triggerDownload(blob, filename){
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download=filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(()=>URL.revokeObjectURL(url),15000);
}
function setBtnLabel(id, txt, dis){ const b=document.getElementById(id); if(b){b.textContent=txt;b.disabled=dis;} }

// ─── FFMPEG SETUP ───────────────────────────────────────────────
let ffmpegLib = null;
let ffmpegReady = false;

async function initFFmpeg(){
  try{
    const FFmpegModule = await import('https://cdn.jsdelivr.net/npm/@ffmpeg/ffmpeg@0.12.7/+esm');
    ffmpegLib = new FFmpegModule.FFmpeg();
    const baseURL = 'https://unpkg.com/@ffmpeg/core@0.12.6/dist/umd/';
    await ffmpegLib.load({
      coreURL: baseURL + 'ffmpeg-core.js',
      wasmURL: baseURL + 'ffmpeg-core.wasm',
    });
    ffmpegReady = true;
    console.log('FFmpeg ready!');
  }catch(e){
    console.log('FFmpeg load error:',e);
    ffmpegReady = false;
  }
}

// Start loading FFmpeg
initFFmpeg();

// ─── CLEAN MP4 EXPORT WITH FFMPEG.WASM ─────────────────────────────────────
// This version creates a proper MP4 file

async function exportMp4FFmpeg(){
  // Try fresh FFmpeg load if not ready
  if(!ffmpegReady || !ffmpegLib){
    try{
      await initFFmpeg();
    }catch(e){}
  }
  
  if(!ffmpegReady || !ffmpegLib){
    alert('FFmpeg loading... Click export again in a few seconds.');
    return;
  }
  
  const lines=parseScript(document.getElementById('scriptInput').value);
  if(!lines.length){ alert('No script lines!'); return; }
  
  setBtnLabel('exportBtn','⏳ FFmpeg...',true);
  setExportProgress(0,'Preparing frames…');
  
  const FPS=S.fps;
  const frameDurMs=1000/FPS;
  
  // Set up offscreen canvas
  const offCanvas=document.createElement('canvas');
  offCanvas.width=canvas.width; offCanvas.height=canvas.height;
  const offCtx=offCanvas.getContext('2d');
  const _rc=canvas,_rx=ctx; canvas=offCanvas; ctx=offCtx;
  
  const ldArr=lines.map((l,i)=>buildLineData(l,globalSeed*997+i*3571));
  ldArr.forEach(ld=>layoutWords(ld));
  
  const totalFrameCount=ldArr.reduce((s,ld)=>s+Math.ceil((ld.words.length*S.wDelay+700)/frameDurMs)+Math.ceil(S.holdDur/frameDurMs)+Math.ceil(S.exitDur/frameDurMs),0);
  
  // Render and save frames to files
  let fakeTime=0,totalFrames=0;
  const frameData=[];
  
  for(let idx=0;idx<ldArr.length;idx++){
    const ld=ldArr[idx]; ld.words.forEach(w=>{w._particled=false;w.entered=false;});
    const inF=Math.ceil((ld.words.length*S.wDelay+700)/frameDurMs);
    const hF=Math.ceil(S.holdDur/frameDurMs);
    const eF=Math.ceil(S.exitDur/frameDurMs);
    
    for(let f=0;f<inF;f++){
      const el=(f/FPS)*1000;fakeTime+=frameDurMs;
      offCtx.clearRect(0,0,offCanvas.width,offCanvas.height);window.drawBg();
      ld.words.forEach((w,i)=>{const wS=i*S.wDelay;if(el<wS)return;const prog=(el-wS)*1.4;window.drawWord(w,prog,fakeTime);if(prog>380)w.entered=true;});
      totalFrames++;
      frameData.push(offCanvas.toDataURL('image/png').split(',')[1]);
      setExportProgress(Math.round(totalFrames/totalFrameCount*80),`Frame ${totalFrames}/${totalFrameCount}`);
      await new Promise(r=>setTimeout(r,5));
    }
    for(let f=0;f<hF;f++){
      fakeTime+=frameDurMs;offCtx.clearRect(0,0,offCanvas.width,offCanvas.height);window.drawBg();
      ld.words.forEach(w=>{window.drawWord(w,500,fakeTime);w.entered=true;});
      totalFrames++;
      frameData.push(offCanvas.toDataURL('image/png').split(',')[1]);
      setExportProgress(Math.round(totalFrames/totalFrameCount*80),`Frame ${totalFrames}/${totalFrameCount}`);
      await new Promise(r=>setTimeout(r,5));
    }
    for(let f=0;f<eF;f++){
      fakeTime+=frameDurMs;offCtx.clearRect(0,0,offCanvas.width,offCanvas.height);window.drawBg();
      ld.words.forEach((w,i)=>{const prog=600-f*1.4;window.drawWord(w,prog,fakeTime);});
      totalFrames++;
      frameData.push(offCanvas.toDataURL('image/png').split(',')[1]);
      setExportProgress(Math.round(totalFrames/totalFrameCount*80),`Frame ${totalFrames}/${totalFrameCount}`);
      await new Promise(r=>setTimeout(r,5));
    }
  }
  
  canvas=_rc; ctx=_rx;
  
  try{
    setExportProgress(85,'Encoding MP4…');
    
    // Write frames to FFmpeg virtual file system
    for(let i=0;i<frameData.length;i++){
      const data = Uint8Array.from(atob(frameData[i]), c => c.charCodeAt(0));
      await ffmpegLib.writeFile(`frame${String(i).padStart(5,'0')}.png`, data);
    }
    
    // Run FFmpeg command to create MP4 video
    await ffmpegLib.exec([
      '-framerate', String(FPS),
      '-i', 'frame%05d.png',
      '-c:v', 'libx264',
      '-pix_fmt', 'yuv420p',
      '-crf', '18',
      '-preset', 'ultrafast',
      'output.mp4'
    ]);
    
    // Read the output file
    const outputData = await ffmpegLib.readFile('output.mp4');
    const blob = new Blob([outputData], { type: 'video/mp4' });
    triggerDownload(blob, 'typoreel.mp4');
    
  }catch(e){
    console.log('FFmpeg export error:',e);
    alert('FFmpeg export failed: ' + e.message + '. Download started as WebM instead.');
    await doExport(); // fallback
    return;
  }
  
  setExportProgress(100,'✓ MP4 Downloaded!');
  setBtnLabel('exportBtn','🎬 MP4',false);
  setTimeout(hideExportProgress,4000);
  startAnim();
}

