  const sxSlR=document.getElementById('shadowXSlider'),sySlR=document.getElementById('shadowYSlider');
  const sxVlR=document.getElementById('shadowXVal'),syVlR=document.getElementById('shadowYVal');
  if(sxSlR){sxSlR.value=S.shadowX;sxVlR.textContent=S.shadowX;}
