const BG={
  current:'none',blend:'source-over',opacity:1,scale:1,fit:'cover',
  overlay:'none',overlayInt:0.5,syncOn:false,
  _imgCache:{},_imgOrder:['alps','pixel_mountain','forest','valley','sunset'],
  init(){
    const opSl=document.getElementById('bgOpacSlider');
    const opVl=document.getElementById('bgOpacVal');
    opSl&&opSl.addEventListener('input',()=>{BG.opacity=+opSl.value/100;opVl.textContent=opSl.value+'%';});
    const scSl=document.getElementById('bgScaleSlider');
    const scVl=document.getElementById('bgScaleVal');
    scSl&&scSl.addEventListener('input',()=>{BG.scale=+scSl.value/100;scVl.textContent=scSl.value+'%';});
    const ovSl=document.getElementById('bgOvIntSlider');
    const ovVl=document.getElementById('bgOvIntVal');
    ovSl&&ovSl.addEventListener('input',()=>{BG.overlayInt=+ovSl.value/100;ovVl.textContent=ovSl.value+'%';});
    Object.entries(BG_IMAGES).forEach(([k,src])=>{const img=new Image();img.src=src;BG._imgCache[k]=img;});
    const input=document.getElementById('bgAddImageInput');
    if(input)input.addEventListener('change',function(){
      const file=this.files[0];if(!file)return;
      const reader=new FileReader();
      reader.onload=function(e){
        const key='custom_'+Date.now();
        const label=file.name.replace(/\.[^.]+$/,'').slice(0,14);
        const img=new Image();img.src=e.target.result;
        BG._imgCache[key]=img;BG._imgOrder.push(key);
        const grid=document.querySelector('.bg-thumb-grid');
        if(grid){
          const div=document.createElement('div');
          div.className='bg-thumb';div.dataset.bgimg=key;
          div.onclick=()=>BG.setImg(key);
          div.innerHTML='<img src="'+e.target.result+'" alt="'+label+'" style="width:100%;height:100%;object-fit:cover;display:block"><div class="bg-thumb-label">'+label+'</div>';
          grid.appendChild(div);
        }
        BG.setImg(key);
      };reader.readAsDataURL(file);
    });
  },
  setImg(key){
    BG.current=key;
    document.querySelectorAll('.bg-thumb').forEach(t=>t.classList.toggle('active',t.dataset.bgimg===key));
  },
  setBlend(el,val){
    BG.blend=val;
    document.querySelectorAll('.blend-btn[data-blend]').forEach(b=>b.classList.remove('active'));
    el.classList.add('active');
  },
  setFit(el,val){
    BG.fit=val;
    document.querySelectorAll('.blend-btn[data-fit]').forEach(b=>b.classList.remove('active'));
    el.classList.add('active');
  },
  setOverlay(el,val){
    BG.overlay=val;
    document.querySelectorAll('.overlay-chip').forEach(b=>b.classList.remove('active'));
    el.classList.add('active');
  },
  toggleSync(){
    BG.syncOn=!BG.syncOn;
    ['syncBadge','syncBadge2'].forEach(id=>{
      const b=document.getElementById(id);if(!b)return;
      b.textContent=BG.syncOn?'SYNC ON':'SYNC OFF';
      b.className='sync-badge '+(BG.syncOn?'on':'off');
    });
  },
  onLineChange(idx){
    if(!BG.syncOn)return;
    const key=BG._imgOrder[idx%BG._imgOrder.length];
    BG.setImg(key);
  },
  randomise(){
    const keys=Object.keys(BG_IMAGES);
    BG.setImg(keys[Math.floor(Math.random()*keys.length)]);
    const blends=['source-over','multiply','screen','overlay','soft-light','color-dodge','difference'];
    const b=blends[Math.floor(Math.random()*blends.length)];
    BG.blend=b;
    document.querySelectorAll('.blend-btn[data-blend]').forEach(btn=>btn.classList.toggle('active',btn.dataset.blend===b));
    const opac=40+Math.floor(Math.random()*60);
    BG.opacity=opac/100;
    const sl=document.getElementById('bgOpacSlider');if(sl)sl.value=opac;
    const vl=document.getElementById('bgOpacVal');if(vl)vl.textContent=opac+'%';
  },
  randomiseAll(){
    BG.randomise();
    const ovs=['none','dark','warm','cool','vignette','grain','duotone','scanlines'];
    const ov=ovs[Math.floor(Math.random()*ovs.length)];
    BG.overlay=ov;
    document.querySelectorAll('.overlay-chip').forEach(c=>c.classList.toggle('active',c.dataset.ov===ov));
    const fits=['cover','contain','stretch','tile'];
    const fit=fits[Math.floor(Math.random()*fits.length)];
    BG.fit=fit;
    document.querySelectorAll('.blend-btn[data-fit]').forEach(b=>b.classList.toggle('active',b.dataset.fit===fit));
  },
  drawToCanvas(tCanvas,tCtx){
    if(BG.current==='none')return false;
    const img=BG._imgCache[BG.current];
    if(!img||!img.complete||!img.naturalWidth)return false;
    const W=tCanvas.width,H=tCanvas.height;
    const iW=img.naturalWidth,iH=img.naturalHeight;
    tCtx.save();
    tCtx.globalAlpha=BG.opacity;
    tCtx.globalCompositeOperation=BG.blend;
    if(BG.fit==='tile'){
      const pat=tCtx.createPattern(img,'repeat');
      tCtx.fillStyle=pat;tCtx.fillRect(0,0,W,H);
    } else {
      let dw,dh,dx,dy;
      const sc=BG.scale;
      if(BG.fit==='stretch'){dw=W*sc;dh=H*sc;dx=(W-dw)/2;dy=(H-dh)/2;}
      else if(BG.fit==='contain'){const r=Math.min(W/iW,H/iH)*sc;dw=iW*r;dh=iH*r;dx=(W-dw)/2;dy=(H-dh)/2;}
      else{const r=Math.max(W/iW,H/iH)*sc;dw=iW*r;dh=iH*r;dx=(W-dw)/2;dy=(H-dh)/2;}
      tCtx.drawImage(img,dx,dy,dw,dh);
    }
    tCtx.restore();
    BG.applyOverlay(tCanvas,tCtx,W,H);
    return true;
  },
  applyOverlay(cv,cx,W,H){
    if(BG.overlay==='none')return;
    const a=BG.overlayInt;
    cx.save();
    if(BG.overlay==='dark'){cx.globalAlpha=a*.8;cx.fillStyle='#000';cx.fillRect(0,0,W,H);}
    else if(BG.overlay==='warm'){cx.globalAlpha=a*.5;cx.globalCompositeOperation='overlay';cx.fillStyle='#c84010';cx.fillRect(0,0,W,H);}
    else if(BG.overlay==='cool'){cx.globalAlpha=a*.5;cx.globalCompositeOperation='overlay';cx.fillStyle='#1040a0';cx.fillRect(0,0,W,H);}
    else if(BG.overlay==='vignette'){const g=cx.createRadialGradient(W/2,H/2,H*.2,W/2,H/2,H*.85);g.addColorStop(0,'rgba(0,0,0,0)');g.addColorStop(1,'rgba(0,0,0,'+a*.9+')');cx.fillStyle=g;cx.fillRect(0,0,W,H);}
    else if(BG.overlay==='grain'){cx.globalAlpha=a*.18;for(let i=0;i<W*H*.06;i++){const gx=Math.random()*W,gy=Math.random()*H,gb=Math.random()>.5?255:0;cx.fillStyle='rgba('+gb+','+gb+','+gb+','+Math.random()+')';cx.fillRect(gx,gy,1.5,1.5);}}
    else if(BG.overlay==='duotone'){const pal=PALETTES[S.pal]||PALETTES.retro_warm;cx.globalAlpha=a*.4;cx.globalCompositeOperation='multiply';const g2=cx.createLinearGradient(0,0,W,H);g2.addColorStop(0,pal[0]||'#c04838');g2.addColorStop(1,pal[2]||'#486898');cx.fillStyle=g2;cx.fillRect(0,0,W,H);}
    else if(BG.overlay==='scanlines'){cx.globalAlpha=a*.35;for(let sy=0;sy<H;sy+=3){cx.fillStyle='rgba(0,0,0,.8)';cx.fillRect(0,sy,W,1);}}
    cx.restore();
  }
};

// Patch drawBg to paint BG image first
const _origDrawBg=drawBg;
window.drawBg=function(){
  if(BG.current!=='none'){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    BG.drawToCanvas(canvas,ctx);
    if(S.bgMode!=='transparent')_origDrawBg();
  } else {
    _origDrawBg();
  }
};

// Sync: watch active line-queue dot changes
(function(){
  let _last=-1;
  setInterval(()=>{
    const all=document.querySelectorAll('.lq-dot');
    all.forEach((d,i)=>{if(d.classList.contains('active')&&i!==_last){_last=i;BG.onLineChange(i);}});
  },200);
})();

BG.init();

